    bool tryUniqueWhileSharedWithoutSafety = false;
    {
        ConditionalSharedLockGuard<ConditionalSharedMutex> sharedGuard(mutex);
        tryUniqueWhileSharedWithoutSafety = mutex.try_lock();
        if (tryUniqueWhileSharedWithoutSafety) {
            mutex.unlock();
