    auto varB = var(b);
    auto varC = var(c);

    // Build logical expressions using overloaded operators:
    // andReact  := (A && B)
    // orReact   := (A && B) || C
    auto andReact = expr(varA && varB);
    auto orReact = expr((varA && varB) || varC);

    const bool initialAnd = andReact.get();
    const bool initialOr = orReact.get();

